class Solution:
    def maxScore(self, nums: List[int]) -> int:
        n = len(nums)
        m = n // 2
        gcds = [[0] * n for _ in range(n)]
        for i in range(n):
            for j in range(i + 1, n):
                gcds[i][j] = gcds[j][i] = gcd(nums[i], nums[j])

        dp = [0] * (1 << n)
        for mask in range(1 << n):
            bits = bin(mask).count('1')
            if bits % 2:
                continue
            k = bits // 2 + 1
            for i in range(n):
                if not (mask & (1 << i)):
                    for j in range(i + 1, n):
                        if not (mask & (1 << j)):
                            new_mask = mask | (1 << i) | (1 << j)
                            dp[new_mask] = max(dp[new_mask], dp[mask] + k * gcds[i][j])
        return dp[(1 << n) - 1]
